INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('immigration-1aab856d-moex-00010', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '全社會防衛韌性基本上涉及國土安全之鄉鎮安全工作，而推動全社會防衛韌性之目的是為讓每個 人在緊急危難時找到自己能有所貢獻的最佳位置，以保護自己、貢獻社會、嚇阻來犯的敵人。而 我國國家安全會議也正式說明全社會防衛韌性之三大目標，下列何者並非是此三大目標之一？', '["繼續維持政府的持續運作", "維持社會民生核心功能的持續運作", "必要的時候支持軍事的行動", "戰略物資盤整暨維生配送"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00011', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '各國在強化國境管理作為方面，除了在國境線上建造國境圍牆外，國際社會亦運用之相關措施不 包含下列那一項？', '["精密之雷達系統", "移動式與熱感應式器材", "設備端通訊監察系統", "結合個人生物特徵資料之自動化辨識系統"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00012', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '國境管理之雙重目的是希望有助於平衡國家在促進人流跨境移動和維持安全方面的利益，而要實 現這種平衡取決於國境管理政策和針對四個工作領域的「干預措施」，此四個領域分別是國境管 理資訊系統、身分管理、整合性國境管理以及下列何種領域之管理？', '["移民定罪系統管理", "人道主義國境管理", "一站式邊防哨所安全管理", "航前旅客資訊系統管理"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00013', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '美國於 2021 年 6 月發布首份「打擊國內恐怖主義國家戰略」(National Strategy for Counter Domestic Terrorism)，該文件在國家戰略中指出，國內暴力極端分子，尤其是認同那一種主義與 反政府民兵意識形態者，對美國構成最持久和最致命的威脅？', '["理想主義", "白人至上主義", "個人主義", "共產主義"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00014', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '歐盟執委會（European Commission）於今年3月提出何項計畫？該計畫如獲通過，未來歐盟 國家將可在第三國設置遣返中心，將非法移民或庇護遭拒者送至第三國，但排除有幼童的家庭 或孤身兒童：', '["盧安達庇護計畫（RwandaAsylumPlan）", "人道假釋計畫（HumanitarianParole）", "童年抵達者暫緩驅逐辦法（DACA）", "歐洲遣返系統（EuropeanSystemforReturns）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00015', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '根據歐盟訂定之關鍵基礎設施涵蓋之部門，不包含下列那一個部門？', '["醫療健康", "太空", "銀行", "信用卡"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00016', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '依據新住民基本法第7條之規定，政府應每幾年進行相關支持事項之調查和擬定計畫，並將調查 結果公開於網站？', '["1年", "2年", "3年", "5年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00017', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '我國新住民人數至114年2月已逾60萬人，為落實憲法保障多元文化精神及宣示政府維護新住 民權益決心，立法院已於113年7月16日三讀通過新住民基本法，並經總統於同年8月12日制 定公布。下列新住民基本法有關中央和地方政府之敘述，何者錯誤？', '["本法主管機關為內政部", "內政部已完成設置「新住民事務專責中央三級行政機關」，統籌規劃、研究、諮詢、協調、推 動、促進新住民就學、就業、培力、關懷協助及多元服務之相關事宜", "行政院於104年6月16日成立新住民事務協調會報，將相關新住民事務提升至行政院層級， 由內政部移民署擔任幕僚單位，以跨部會協調及統整資源", "為提升新住民在臺生活適應能力，使其能及早順利適應我國生活環境，共創多元文化社會，內 政部補助全國22個直轄市、縣（市）政府辦理生活適應輔導班、種子研習營、生活適應宣導 及推廣多元文化活動等"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00018', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '入出國及移民法第15條第5項規定，臺灣地區無戶籍國民未經許可入國，或經許可入國已逾停 留、居留或限令出國之期限者，內政部移民署得逕行強制其出國，並得限制再入國。有關臺灣地 區無戶籍國民強制出國處理辦法，下列敘述何者錯誤？', '["經查獲之無戶籍國民未涉有刑事案件者，或涉有刑事案件而移送司法機關偵辦，未經依法羈押、 拘提、管收或限制出國者，由內政部移民署依法為相關處置", "內政部移民署執行無戶籍國民之強制出國，應檢查受強制出國之無戶籍國民身體與攜帶之物及 派員戒護至機場、港口，監視其出國，並將其證照或旅行文件交由機、船長或其授權人員保管。 有抗拒出國或脫逃之虞者，內政部移民署得派員護送至應遣送之國家或地區", "強制已取得居留或定居許可之無戶籍國民出國前，應召開審查會審查，於決議前，不執行強制 出國。但有本法第36條第4項但書各款情形之一者，得不經審查會審查，逕行強制出國", "受任律師於陳述意見程序或審查會進行時，不得在場陪同"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00019', 'immigration-1aab856d', 'immigration-1aab856d-moex-114-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '外國專業人才在我國從事專業工作，合法連續居留5年，平均每年居住183日以上，得向內政部 移民署申請永久居留，但須符合下列各款要件，何者錯誤？', '["符合我國國家利益", "有相當之財產或技能，足以自立", "無不良素行，或無警察刑事紀錄證明之刑事案件紀錄", "成年（18歲以上）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:52+00:00", "source_pdf_sha1": "f309a77206ce", "answer_pdf_sha1": "8dae9df4e2a0", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "807", "s": "0714", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
